import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-settings.e7FrcLCc.js";const s=JSON.parse(`{"title":"Fabric auf macOS installieren","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Fabric auf macOS.","frontmatter":{"title":"Fabric auf macOS installieren","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Fabric auf macOS.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"de_de/players/installing-fabric/macos.md","filePath":"translated/de_de/players/installing-fabric/macos.md","lastUpdated":1770561656000}`);var c={name:`de_de/players/installing-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric auf macOS installieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric auf macOS installieren”">​</a></h1><div class="info custom-block"><p class="custom-block-title">VORAUSSETZUNGEN</p><p>Du musst möglicherweise <a href="./../installing-java/macos">Java installieren</a>, vor du die <code>.jar</code> ausführst.</p></div><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Den Fabric Installer herunterladen <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Den Fabric Installer herunterladen”">​</a></h2><p>Lade die <code>.jar</code> Version des Fabric Installer von der <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a> herunter, indem du auf <code>Download installer (Universal/.JAR)</code> klickst.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Den Fabric Installer ausführen <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Den Fabric Installer ausführen”">​</a></h2><p>Schließe vor dem Ausführen des Installers zuerst Minecraft und den Minecraft Launcher.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Du erhältst möglicherweise eine Warnung, dass Apple die <code>.jar</code> nicht verifizieren konnte. Um dies zu umgehen, öffne Systemeinstellungen &gt; Datenschutz und Sicherheit und klicke dann auf <code>Dennoch öffnen</code>. Bestätige und gebe, wenn aufgefordert, dein Administrator Passwort ein.</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="macOS Systemeinstellungen" loading="lazy"></p></div><p>Sobald du den Installer öffnest, solltest du eine Oberfläche wie diese sehen:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer mit &quot;Install&quot; hervorgehoben" loading="lazy"></p><p>Wähle deine gewünschte Minecraft-Version aus und klicke auf <code>Installieren</code>. Stelle sicher, dass die Option <code>Profil erstellen</code> aktiviert ist.</p><h3 id="installing-via-homebrew" tabindex="-1">Installation über Homebrew <a class="header-anchor" href="#installing-via-homebrew" aria-label="Permalink to “Installation über Homebrew”">​</a></h3><p>Wenn du bereits <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a> installiert hast, kannst du stattdessen den Fabric Installer mit <code>brew</code> installieren:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-finish-setup" tabindex="-1">3. Einrichtung abschließen <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Einrichtung abschließen”">​</a></h2><p>Öffne den Minecraft Launcher, sobald die Installation abgeschlossen ist. Wähle dann das Fabric Profil aus dem Versions-Dropdown-Menü aus und klicke auf Spielen.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher mit dem Fabric Profil ausgewählt" loading="lazy"></p><p>Du kannst jetzt Mods zu deinem Spiel hinzufügen. Weitere Informationen findest du in der Anleitung <a href="./../finding-mods">Vertrauenswürdige Mods finden</a>.</p><p>Wenn du Probleme hast, kannst du gerne im <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> um Hilfe bitten.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};